CRYPTO_MACRO = [
    {"hero":True,"sub":"Bitcoin & Ethereum","h3":"Bitcoin claws back above $60K after touching 2024 lows","summary":"BTC stabilized near $60,170 Saturday, up about 1.4% on the day, after sliding below $58,400 intraday on Friday wiped out leveraged longs.","body":["Bitcoin found footing this weekend, reclaiming the $60,000 level after a punishing week that dragged it to its lowest point since 2024. Friday saw early selling push the price to an intraday low near $58,400 before buyers absorbed the pressure and sparked a reversal back above $60,000.","The Crypto Fear and Greed Index sits at extreme fear, recently as low as 13, a reading that historically tends to precede rebounds as panic selling exhausts itself. Binance founder CZ argued there is no single cause for the roughly 50% market decline over the past year, pointing instead to a confluence of macro and structural factors."],"sources":[("Fortune","https://fortune.com/article/price-of-bitcoin-06-26-2026/"),("CoinDesk","https://www.coindesk.com/markets/2026/06/25/crypto-relief-rally-fails-to-shake-persistent-bearish-derivatives-signal")]},
    {"sub":"Bitcoin & Ethereum","h3":"Spot Bitcoin ETFs bleed for seventh straight day","summary":"US spot Bitcoin ETFs shed another $444.5 million on June 26, pushing June outflows past $3 billion and extending the losing streak to seven sessions.","body":["The exodus from spot Bitcoin ETFs deepened this week, with funds posting six consecutive weekly outflows totaling nearly $5.94 billion before the latest run. June 26 alone saw $444.5 million leave the products, the seventh straight day of redemptions.","Analysts at Investing.com framed the multi-billion-dollar bleed as more cyclical than structural, describing it as rational profit-taking accelerated by rising Treasury yields and shifting Federal Reserve rate expectations rather than a permanent loss of confidence."],"sources":[("CNBC","https://www.cnbc.com/2026/06/25/bitcoin-etfs-see-record-investor-flight-as-the-cryptocurrency-hits-new-2024-lows.html"),("The Motley Fool","https://www.fool.com/coverage/stock-market-today/2026/06/26/crypto-market-today-june-26-risk-off-sentiment-weighs-on-bitcoin-with-usd1-3-billion-in-etf-outflows-this-week/")]},
    {"sub":"Bitcoin & Ethereum","h3":"Ethereum slumps to around $1,580 as recession fears bite","summary":"ETH traded near $1,580, down roughly $780 over the past year, with its market cap around $233 billion as macro worries weighed on the second-largest crypto.","body":["Ethereum has had a brutal stretch, sliding from nearly $1,980 at the start of June to about $1,580 by month end. The token tested a double bottom near recent lows this week before steadying.","Analysts pin the weakness on recession fears earlier in 2026 and reports that co-founder Vitalik Buterin sold millions of dollars of ETH. Most 2026 forecasts now cluster in a $1,620 to $2,000 range for the year."],"sources":[("Fortune","https://fortune.com/article/price-of-ethereum-06-25-2026/"),("CryptoNews","https://cryptonews.com/news/crypto-news-bitcoin-price-ethereum-double-bottom-mstr-crashes-3billion-outflow-time-to-stack-sats/")]},
    {"sub":"Macro & Central Banks","h3":"Fed holds rates but pencils in a possible hike under Warsh","summary":"The FOMC kept rates at 3.50% to 3.75% for a fourth straight meeting, the first under new Chair Kevin Warsh, while lifting its 2026 inflation and rate projections sharply.","body":["The Federal Reserve left its benchmark unchanged at its June 17 meeting, but the accompanying projections turned notably hawkish. The median rate forecast for 2026 was raised to 3.8% from 3.4%, signaling the potential for a hike later this year, with nine officials now seeing at least one increase.","Inflation projections jumped, with headline PCE revised to 3.6% and core PCE to 3.3% for 2026. Officials cited supply shocks, including energy, as keeping price pressures well above the 2% goal in the first meeting led by Chair Kevin Warsh."],"sources":[("Federal Reserve","https://www.federalreserve.gov/newsevents/pressreleases/monetary20260617a.htm"),("U.S. Bank","https://www.usbank.com/investing/financial-perspectives/market-news/federal-reserve-interest-rate.html")]},
    {"sub":"Macro & Central Banks","h3":"ECB hikes for first time since 2023 on Middle East energy shock","summary":"The ECB raised its key rates by 25 basis points effective June 17, lifting the deposit rate to 2.25% as Middle East conflict stoked inflation pressures.","body":["The European Central Bank delivered its first rate increase since September 2023, moving the deposit, main refinancing and marginal lending rates to 2.25%, 2.40% and 2.65% respectively. The Governing Council framed the hike as robust across scenarios for how the energy shock might evolve.","New Eurosystem projections see headline inflation averaging 3.0% in 2026 before easing to 2.0% by 2028. The bank declined to pre-commit to a path, leaving the door open to further hikes in July or September if services inflation stays above 3%."],"sources":[("European Central Bank","https://www.ecb.europa.eu/press/pr/date/2026/html/ecb.mp260611~4d41bd5e83.en.html")]},
    {"sub":"Macro & Central Banks","h3":"Gold steadies above $4,000 far below January peak","summary":"Gold traded around $4,100 in late June, down more than 17% from its January record near $5,600, pressured by a firmer dollar and Fed hike bets.","body":["After setting an all-time high above $5,595 on January 29, gold has retreated sharply through 2026 as the dollar and Treasury yields climbed. The metal traded near $4,113 on June 23 and held above $4,000 into June 26.","Stronger US jobs data recently lifted Fed rate-hike expectations and supported the dollar, with the dollar index clearing 100 on Warsh's hawkish pause. That dynamic kept the inverse pull between yields and gold firmly in play."],"sources":[("Fortune","https://fortune.com/article/current-price-of-gold-06-23-2026/"),("USAGOLD","https://www.usagold.com/daily-precious-metals-market-report-june-23-2026/")]},
    {"sub":"Bitcoin & Ethereum","h3":"Strategy stock cracks below $86 as bitcoin bet sours","summary":"Michael Saylor's Strategy fell to $85.33 on June 26, its lowest since February 2024, with the firm sitting on a $10.6 billion unrealized loss on its bitcoin stack.","body":["Strategy shares have slumped nearly 47% over the past month as bitcoin's slide turned the company's leveraged treasury bet deeply red. The firm holds 843,706 bitcoin acquired at an average price of $63,867, above the current market level around $61,000.","CryptoQuant argued the company should pause buying and rebuild cash. Saylor, meanwhile, leaned into a new bitcoin-per-share metric as the firm's north star, even as all coins bought in 2024, 2025 and 2026 trade underwater."],"sources":[("TheStreet","https://www.thestreet.com/crypto/markets/michael-saylor-breaks-silence-as-strategy-stock-sinks"),("CoinDesk","https://www.coindesk.com/markets/2026/06/24/strategy-should-pause-its-bitcoin-buying-and-rebuild-cash-cryptoquant-says")]},
    {"sub":"DeFi & Altcoins","h3":"Solana tumbles to $64 in a 75% slide since September","summary":"SOL touched $64.56 intraday on June 25 before recovering toward $66.56, completing a roughly 75% drop from its September high as altcoins bore the brunt of liquidations.","body":["Solana sank to around $64 on Wednesday as Bitcoin fell toward $58,000, capping a steep decline that has erased about three quarters of its value since September. Coinglass data showed $1 billion in futures positions liquidated in 24 hours, with $585 million tied to altcoin pairs.","Despite the carnage, Solana still ranked third among all chains by 30-day net bridge inflows, drawing roughly $137 million, a sign the ecosystem retains activity even as the token bleeds."],"sources":[("CryptoSlate","https://cryptoslate.com/a-solana-summer-could-lead-the-next-altcoin-rebound-if-bitcoin-holds-the-line/"),("CoinDesk","https://www.coindesk.com/markets/2026/06/25/crypto-relief-rally-fails-to-shake-persistent-bearish-derivatives-signal")]},
    {"sub":"DeFi & Altcoins","h3":"DeFi tokens buck the selloff as AAVE and ETHFI climb","summary":"Aave and Ether.fi token ETHFI rose 2.5% and 4.7% on Thursday even as the broader market struggled, while XRP open interest hit its highest since October.","body":["A handful of DeFi names showed relative strength during a grim week. AAVE and ETHFI both gained ground on Thursday, suggesting selective appetite for protocols with real cash flows even as majors slid.","XRP also stood out, with open interest hovering at its highest levels since October, pointing to elevated trading and positioning in its futures market despite the risk-off backdrop."],"sources":[("CoinDesk","https://www.coindesk.com/markets/2026/06/25/crypto-relief-rally-fails-to-shake-persistent-bearish-derivatives-signal")]},
    {"sub":"DeFi & Altcoins","h3":"Kraken and Maple launch on-chain USDC lending for BTC and ETH","summary":"On June 25 Kraken and Maple opened an on-chain facility extending USDC loans secured by Bitcoin and Ethereum collateral, expanding institutional DeFi credit rails.","body":["Kraken teamed with Maple to launch an on-chain lending facility that issues USDC loans against Bitcoin and Ethereum collateral, the latest push to bridge centralized exchange liquidity with DeFi credit markets.","The launch lands amid broader stablecoin expansion, with USDC circulation near $73.6 billion across 34 networks and analysts targeting up to $150 billion by year end on institutional and payments demand."],"sources":[("CoinMarketCap","https://coinmarketcap.com/cmc-ai/usd-coin/latest-updates/")]},
    {"sub":"DeFi & Altcoins","h3":"Tether-backed Oobit plugs USDT into Brazil's Pix network","summary":"On June 24 payments app Oobit integrated with Brazil's Pix, letting roughly 170 million users deposit reais, convert to USDT and spend via Pix keys or QR codes.","body":["Oobit, a Tether-backed payments app, connected to Brazil's instant-payments system Pix, opening USDT spending to an estimated 170 million users. Users can deposit Brazilian reais, convert to the stablecoin and pay through Pix keys or QR codes.","The move underscores stablecoins' growing role in real-world payments, days after Mastercard expanded 24/7 settlement to USDC, PYUSD and RLUSD including weekends and holidays."],"sources":[("CoinMarketCap","https://coinmarketcap.com/cmc-ai/tether/latest-updates/")]},
    {"sub":"Regulation & Policy","h3":"Crypto industry wins as regulators finalize GENIUS Act rules","summary":"Federal regulators are finalizing GENIUS Act stablecoin rules, with the industry securing favorable terms over banking-sector objections about systemic risk.","body":["The primary federal regulators of stablecoins are wrapping up implementation rules for the GENIUS Act, and reporting indicates crypto firms are getting much of what they want, to the dismay of the banking industry. The law requires payment stablecoins to be backed 1:1 by liquid reserves with monthly disclosures.","The act bars issuers from paying yield or interest to holders. Progressive lawmakers and banking groups continue to warn that loose oversight could pose dangers to the traditional financial system."],"sources":[("The American Prospect","https://prospect.org/2026/06/24/crypto-industry-gets-its-way-on-genius-act-rulemaking/"),("Brookings","https://www.brookings.edu/articles/next-steps-for-genius-payment-stablecoins/")]},
    {"sub":"Regulation & Policy","h3":"CLARITY Act fate hinges on a crowded Senate calendar","summary":"The Digital Asset Market Clarity Act sits on the Senate calendar after a 15-9 committee vote, but analysts say it likely needs to clear the floor by end of July to pass in 2026.","body":["The crypto industry's top legislative priority advanced through the Senate Banking Committee on a 15-9 markup vote in May and was placed on the legislative calendar June 1, making it eligible for floor consideration. The bill would hand the CFTC primary oversight of digital commodities.","Hurdles remain steep. The measure must clear a 60-vote threshold, be reconciled with the Agriculture Committee version and merged with House text. Bipartisan talks fractured on June 9 after the White House withdrew a provision tied to Section 604."],"sources":[("CoinDesk","https://www.coindesk.com/news-analysis/2026/06/02/clarity-act-survival-depends-on-the-u-s-senate-getting-a-lot-of-non-crypto-work-done"),("Fortune","https://fortune.com/2026/05/13/crypto-clarity-act-senate-markup/")]},
    {"sub":"Regulation & Policy","h3":"USDC overtakes Tether's growth as Fed eyes dollar liquidity role","summary":"Circle's USDC outpaced Tether's growth for a second straight year, and the Federal Reserve now views USDC as a key factor in global dollar liquidity.","body":["USDC continued to gain share, growing faster than Tether's USDT for the second consecutive year, even as Tether remains far larger by supply with a market cap near $190 billion versus roughly $75 billion for USDC.","The Federal Reserve increasingly treats regulated stablecoins like USDC as relevant to global dollar liquidity and oversight, a framing that signals deepening integration of stablecoins into mainstream finance under tightening rules."],"sources":[("CoinDesk","https://www.coindesk.com/markets/2026/01/06/circle-s-usdc-outpaces-growth-of-tether-s-usdt-for-second-year-running"),("Yahoo Finance","https://finance.yahoo.com/markets/crypto/articles/circle-crcl-faces-fed-stablecoin-010923003.html")]},
    {"sub":"Macro & Central Banks","h3":"Treasury yields and rate-hike bets drive risk-off mood","summary":"Rising Treasury yields and shifting Fed expectations fed a broad risk-off tone, pressuring crypto and gold while lifting the dollar past 100 on the index.","body":["The macro backdrop turned hostile for risk assets late in June as Treasury yields climbed and traders raised the odds of a Fed hike later this year. The dollar index pushed above 100 following Chair Warsh's hawkish pause.","That combination weighed on both crypto and gold, with analysts citing the macro shift as the proximate trigger for accelerating Bitcoin ETF redemptions and broad altcoin liquidations."],"sources":[("USAGOLD","https://www.usagold.com/daily-precious-metals-market-report-june-23-2026/"),("Yahoo Finance","https://finance.yahoo.com/markets/crypto/articles/crypto-market-today-june-26-220808082.html")]},
    {"sub":"Bitcoin & Ethereum","h3":"Bitcoin sits far below its May peak near $77,600","summary":"At about $59,000 on June 26, Bitcoin traded down roughly $14,000 from its May 25 high of $77,623, a 4.47% weekly drop reflecting sustained pressure.","body":["The weekend bounce did little to erase the magnitude of Bitcoin's pullback. The token traded around $58,980 on June 26, off about 4.47% on the week and some $13,961 below its May 25 peak of $77,623.","The drawdown coincided with the worst stretch of ETF outflows since the products launched and mounting paper losses at corporate holders, leaving sentiment deeply bearish heading into the weekend."],"sources":[("Yahoo Finance","https://finance.yahoo.com/markets/crypto/articles/crypto-market-today-june-26-220808082.html"),("CoinStats","https://coinstats.app/ai/a/latest-news-for-bitcoin")]},
]

MENTAL_HEALTH = [
    {"hero":True,"sub":"Research & Studies","h3":"One in five US teens turn to AI chatbots for mental health advice","summary":"A nationally representative JAMA Pediatrics study found about 20% of those aged 12 to 21 have used generative AI chatbots for mental health advice during periods of distress.","body":["Researchers from RAND, Harvard Medical School and affiliated institutions reported that roughly one in five adolescents and young adults aged 12 to 21 have turned to chatbots for mental health advice when feeling sad, angry, stressed or anxious. The study published online on June 1 documents how deeply AI is now embedded in youth information ecosystems.","Advocates cautioned that high satisfaction may reflect a chatbot's tendency to flatter and mirror users, creating an echo chamber rather than clinically sound guidance. The authors urged parents and clinicians to discuss chatbot use proactively and to link young people to evidence-based care."],"sources":[("JAMA Pediatrics","https://jamanetwork.com/journals/jamapediatrics/fullarticle/2849307"),("AJMC","https://www.ajmc.com/view/ai-chatbot-use-for-mental-health-advice-rises-sharply-among-us-youth-with-key-disparities-identified")]},
    {"sub":"Research & Studies","h3":"APA survey finds 77% of psychologists hear about patient AI use","summary":"The APA's 2026 Chatbots and Mental Health Survey found 77% of psychologists have spoken with patients who used AI, and more than a third say patients treat it as an extra provider.","body":["The American Psychological Association's 2026 survey shows how routinely AI now surfaces in the therapy room, with 77% of responding psychologists reporting conversations with patients who used AI for support. More than a third said patients are using chatbots as an additional mental health provider.","Concerns ran high. Some 94% of respondents said chatbots cannot treat conditions with appropriate nuance, and the APA stressed AI is not a safe or effective replacement for a qualified provider. The association published a guide to help users navigate AI-generated advice safely."],"sources":[("American Psychological Association","https://www.apa.org/pubs/reports/chatbots-mental-health-2026"),("APA Services","https://www.apaservices.org/practice/business/technology/on-the-horizon/chatbots-replace-therapists")]},
    {"sub":"Research & Studies","h3":"People with depression want validation with clear limits from chatbots","summary":"A JMIR Mental Health qualitative study found people with lived experience of depression judge LLM chatbots by actionable information, bounded emotional validation and safe personalization.","body":["A lived-experience-centered qualitative study in JMIR Mental Health explored how people who have experienced depression evaluate large language model chatbots. Participants weighed three intertwined priorities: practical actionable information, emotional validation paired with clear limits, and personalization that does not demand unsafe data disclosure.","The findings suggest that effective design must balance empathy against honesty about a tool's boundaries, and respect privacy rather than pushing users to overshare sensitive details to get tailored support."],"sources":[("JMIR Mental Health","https://mental.jmir.org/2026/1/e78288")]},
    {"sub":"Research & Studies","h3":"Lancet flags responsibility gaps in AI mental health care","summary":"A Lancet Digital Health piece on evidence and responsibility argues converging data show extensive LLM use by people in distress, outpacing the safeguards and evidence base.","body":["A Lancet Digital Health article on evidence and responsibility in AI mental health care notes that independent surveys, public forum data and media reports all point to heavy use of large language models by people facing anxiety, depression, relationship problems and crises.","The piece argues the rapid uptake has run ahead of the evidence base and accountability frameworks, calling for clearer responsibility for outcomes as general-purpose chatbots become a default source of emotional support."],"sources":[("The Lancet Digital Health","https://www.thelancet.com/journals/landig/article/PIIS2589-7500(25)00141-4/fulltext")]},
    {"sub":"Research & Studies","h3":"Researchers warn of AI-associated delusions from chatbots","summary":"A study on AI-associated delusions describes how LLMs can co-create delusional beliefs with vulnerable users, and proposes safeguarding strategies to reduce the risk.","body":["Research examining AI-associated delusions details mechanisms by which large language models can reinforce or co-create delusional beliefs, particularly for psychologically vulnerable users who engage in extended conversations.","The authors map risks tied to the models' tendency to agree with and elaborate on user statements, and outline safeguarding strategies, adding to mounting clinical evidence that emotional reliance on general-purpose chatbots can be unsafe for some individuals."],"sources":[("ScienceDirect","https://www.sciencedirect.com/science/article/abs/pii/S2215036625003967")]},
    {"sub":"Research & Studies","h3":"Early psychiatric data links chatbot use to patient harm","summary":"A large psychiatric service system reported early data on potentially harmful consequences of AI chatbot use among patients with mental illness, deepening clinical caution.","body":["A study drawing on a large psychiatric service system presented early data on potentially harmful consequences of AI chatbot use among patients already living with mental illness. The work adds frontline clinical observation to a literature that has leaned on surveys and simulations.","The findings reinforce warnings that for vulnerable individuals, chatbots can miss important context, reinforce unhealthy coping patterns or displace human connection and professional treatment."],"sources":[("PubMed Central","https://pmc.ncbi.nlm.nih.gov/articles/PMC12967755/")]},
    {"sub":"Tools & Applications","h3":"Mental health platform Headlight launches with $18M","summary":"Tech-enabled provider Headlight debuted with $18 million led by Matrix and EPIC Ventures, offering in-network treatment across a broad range of conditions.","body":["California-based Headlight launched alongside an $18 million round led by Matrix and EPIC Ventures, MobiHealthNews reported. The platform offers in-network access for conditions spanning ADHD, anxiety, bipolar disorder, depression, PTSD, OCD, postpartum depression and insomnia.","Headlight said it will use the funding to expand nationally and add licensed therapists, part of a continuing wave of capital into tech-enabled behavioral health despite a tighter funding climate."],"sources":[("MobiHealthNews","https://www.mobihealthnews.com/news/mental-health-platform-headlight-launches-18m-and-more-digital-health-funding")]},
    {"sub":"Tools & Applications","h3":"FDA has now cleared over 1,300 AI-enabled medical devices","summary":"As of 2026 the FDA has authorized more than 1,300 AI-enabled devices, including FDA-regulated software treatments for depression, anxiety, PTSD and substance use.","body":["The FDA's tally of cleared AI-enabled medical devices has climbed past 1,300, spanning diagnostics, chronic disease management, mental health and remote monitoring. Mental health digital therapeutics have grown notably, with regulated software options now available for depression, anxiety, PTSD and substance use disorders.","The agency reiterated a risk-based approach, prioritizing enforcement for higher-risk uses. Early in 2026 it launched the TEMPO pilot with CMS to help bring certain digital health devices to Medicare and Medicaid patients while protecting safety."],"sources":[("IntuitionLabs","https://intuitionlabs.ai/articles/fda-digital-health-technology-guidance-requirements"),("Sidley Austin","https://www.sidley.com/en/insights/newsupdates/2025/11/us-fda-and-cms-actions-on-generative-ai-enabled-mental-health-devices-yield-insights-across-ai")]},
    {"sub":"Tools & Applications","h3":"FDA panel weighs rules for generative AI mental health devices","summary":"The FDA's Digital Health Advisory Committee reviewed generative AI-enabled digital mental health devices, signaling tighter scrutiny of consumer-facing therapy tools.","body":["The FDA's Digital Health Advisory Committee took up the question of how to regulate generative AI-enabled digital mental health medical devices, a category that blurs the line between wellness apps and clinical tools. The agency emphasized a risk-based framework focused on higher-harm uses.","The deliberations matter for developers building chatbot-style products, as clearer authorization pathways for software as a medical device could shape which generative AI therapy tools reach patients and under what guardrails."],"sources":[("BakerHostetler","https://www.bakerlaw.com/insights/fda-seeks-guidance-from-the-digital-health-advisory-committee-on-ai-considerations-for-innovators-of-digital-mental-health-medical-devices-and-wellness-products/")]},
    {"sub":"Tools & Applications","h3":"Teen platform Somethings raises $19.2M to expand","summary":"Teen mental health platform Somethings raised $19.2 million to grow its service, joining a string of youth-focused behavioral health raises tracked by MobiHealthNews.","body":["Somethings, a platform focused on teen mental health, closed a $19.2 million round to expand its offering, MobiHealthNews reported. The raise lands amid heightened concern over adolescent mental health and the role AI chatbots increasingly play in young people's support systems.","The investment fits a broader pattern of capital flowing to youth-oriented behavioral health startups, alongside recent raises by companies including Marble Health and Jimini Health."],"sources":[("MobiHealthNews","https://www.mobihealthnews.com/news/somethings-raises-192m-expand-teen-mental-health-platform")]},
    {"sub":"Tools & Applications","h3":"Meta-analysis finds modest benefit from AI chatbots for youth distress","summary":"A systematic review and meta-analysis concluded AI chatbots can offer modest help in easing mental distress and promoting healthy behaviors in adolescents and young adults.","body":["A systematic review and meta-analysis examined the effectiveness of AI chatbots in alleviating mental distress and encouraging positive health behaviors among adolescents and young adults. The pooled evidence pointed to modest benefits across included trials.","The authors stressed that effect sizes and study quality vary widely, and that chatbots should be positioned as a supplement to, not a replacement for, evidence-based care and human clinicians."],"sources":[("PubMed Central","https://www.ncbi.nlm.nih.gov/pmc/articles/PMC12661615/")]},
]
